16	const sum = (numbers: number[]): number =>
17	  numbers.reduce((acc, n) => acc + n, 0);
18	
19	// round up to whole G in MHPCO's favor, using epsilon to fight FP error
20	const roundUpInMHPCOFavor = (amount: number): number =>
21	  Math.ceil(amount - FP_EPSILON);
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PRICE = 60;
26	
27	const countByType = (items: Item[]): Map<string, number> =>
28	  items.reduce(
29	    (acc, item) => acc.set(item.type, (acc.get(item.type) ?? 0) + 1),
30	    new Map<string, number>(),
31	  );
32	
33	const typeGroupPremium = (type: string, count: number): number =>
34	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE
35	    ? COMPONENT_BLOCK_PRICE
36	    : count * BASE_PREMIUM[type];
37	
38	const itemsBasePremium = (items: Item[]): number =>
39	  sum(
40	    Array.from(countByType(items), ([type, count]) =>
41	      typeGroupPremium(type, count),
42	    ),
43	  );
44	
45	const CURSE_SURCHARGE_RATE = 0.5;
46	const HIGH_ENCHANTMENT_RATE = 0.3;
47	const HIGH_ENCHANTMENT_THRESHOLD = 5;
48	
49	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
50	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
51	  {
52	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
53	    rate: HIGH_ENCHANTMENT_RATE,
54	  },
55	];
56	
57	const itemSurcharge = (item: Item): number => {
58	  const base = BASE_PREMIUM[item.type];
59	  return sum(
60	    SURCHARGE_RULES.map((rule) => (rule.applies(item) ? base * rule.rate : 0)),
61	  );
62	};
63	
64	const itemSurcharges = (items: Item[]): number =>
65	  sum(items.map(itemSurcharge));
66	
67	const LOYALTY_DISCOUNT_RATE = 0.2;
68	const LOYALTY_YEARS_THRESHOLD = 2;
69	const FOLLOWUP_DISCOUNT_RATE = 0.15;
70	
71	const isLongStanding = (customer: Customer): boolean =>
72	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
73	
74	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
75	  isLongStanding(customer) ? -policyBase * LOYALTY_DISCOUNT_RATE : 0;
76	
77	const firstInsuranceSurcharge = (policyBase: number): number =>
78	  policyBase * FIRST_INSURANCE_RATE;
79	
80	const followupDiscount = (policyBase: number, isFollowup: boolean): number =>
81	  isFollowup ? -policyBase * FOLLOWUP_DISCOUNT_RATE : 0;
82	
83	const policyModifiers = (
84	  policyBase: number,
85	  customer: Customer,
86	  isFollowup: boolean,
87	): number =>
88	  firstInsuranceSurcharge(policyBase) +
89	  loyaltyDiscount(policyBase, customer) +
90	  followupDiscount(policyBase, isFollowup);
91	
92	const quote = (
93	  step: Step,
94	  customer: Customer,
95	  isFollowup: boolean,
96	): { premium: number } => {
97	  const items = step.items;
98	  const policyBase = itemsBasePremium(items);
99	  const total =
100	    policyBase +
101	    itemSurcharges(items) +
102	    policyModifiers(policyBase, customer, isFollowup) +
103	    PROCESSING_FEE;
104	  return { premium: roundUpInMHPCOFavor(total) };
105	};
