107	export const runScenario = (input: unknown): unknown => {
108	  const scenario = input as Scenario;
109	  let quoteCount = 0;
110	  const results = scenario.steps.map((step) => {
111	    const isFollowup = quoteCount > 0;
112	    quoteCount += 1;
113	    return quote(step, scenario.customer, isFollowup);
114	  });
115	  return { results };
116	};
